(function () {
// Strip trailing digits and replace underscores so folder keys like "bread11" or
// "monstera_tree" become "bread" / "monstera tree" for display. CSS capitalizes the
// first letter via text-transform on the label classes.
function prettyLabel(obj) {
    return obj.replace(/\d+$/, '').replace(/_/g, ' ');
}

// Per-(object, column) mesh metrics shown under each image.
// Data is generated by MultipartTexture/update_web_mesh_metrics.py.
const demoMeshMetrics = window.MULTIPART_TEXTURE_MESH_METRICS || { objects: {} };
const inputVariantKeys = new Set(["raw", "target"]);
const galleryConfig = {
    groups: {
        multipart: {
            baseFolder: "comparison_multipart",
            objects: ["cello", "shiba", "water_manhole_cover", "bridge_venetian", "brutalist_building", "CoffeeCart", "drill_press", "robot_arm", "drawer"]
        },
        singlepart: {
            baseFolder: "comparison_singlepart",
            objects: [
                "bear",
                "carved_wooden_elephant",
                "cube",
                "dustpan",
                "hammer",
                "propane_tank",
                "rubber_duck_toy",
                "wet_floor_sign"
            ]
        }
    },
    columns: ["raw", "target", "materialmvp", "hunyuan2_1", "meshy", "trellis2", "unitex", "lumitex", "texgen"],
    labels: {
        raw: "Raw",
        target: "Target Image",
        materialmvp: "MaterialMVP",
        hunyuan2_1: "Hunyuan2.1",
        meshy: "Meshy",
        trellis2: "Trellis",
        unitex: "UniTex",
        lumitex: "LumiTex",
        texgen: "TexGen"
    }
};
let demoColumns = [];

function variantLabel(variant) {
    if (galleryConfig.labels[variant]) return galleryConfig.labels[variant];
    return prettyLabel(variant).replace(/\b\w/g, char => char.toUpperCase());
}

function columnsFromVariants(variants) {
    return (variants || []).map(variant => {
        const column = {
            key: variant,
            label: variantLabel(variant),
            src: variant === "raw" ? "input/raw.png" : (variant === "target" ? "input/target.png" : `${variant}/preview.png`)
        };
        return column;
    });
}

function imageExists(src) {
    return new Promise(resolve => {
        const image = new Image();
        image.onload = () => resolve(true);
        image.onerror = () => resolve(false);
        image.src = src;
    });
}

async function inferGalleryGroupsFromMetrics() {
    const objects = Object.keys(demoMeshMetrics.objects || {});
    const groups = {
        multipart: { objects: [], baseFolder: "comparison_multipart" },
        singlepart: { objects: [], baseFolder: "comparison_singlepart" }
    };

    await Promise.all(objects.map(async (obj) => {
        const singlepartRaw = `static/images/comparison_singlepart/${obj}/input/raw.png`;
        if (await imageExists(singlepartRaw)) {
            groups.singlepart.objects.push(obj);
            return;
        }

        const multipartRaw = `static/images/comparison_multipart/${obj}/input/raw.png`;
        if (await imageExists(multipartRaw)) {
            groups.multipart.objects.push(obj);
        }
    }));

    return groups;
}

function formatMetricNumber(value) {
    return value == null ? '--' : Number(value).toLocaleString('en-US');
}

function formatWatertight(value) {
    if (value === true) return 'WT';
    if (value === false) return 'NWT';
    return '--';
}

function formatInferenceTime(seconds) {
    if (seconds == null || !Number.isFinite(Number(seconds))) return '--';
    const value = Number(seconds);
    if (value < 60) return `${value.toFixed(1)}s`;
    const minutes = Math.floor(value / 60);
    const remaining = Math.round(value % 60);
    return `${minutes}m ${remaining}s`;
}

function escapeAttribute(value) {
    return String(value)
        .replace(/&/g, '&amp;')
        .replace(/"/g, '&quot;')
        .replace(/</g, '&lt;');
}

function metricForCell(obj, key) {
    const objectMetrics = demoMeshMetrics.objects && demoMeshMetrics.objects[obj];
    return objectMetrics ? objectMetrics[key] : null;
}

function isMissingMetric(metric) {
    return !metric || metric.available === false;
}

function resultStatusForCell(obj, key) {
    const metric = metricForCell(obj, key);
    if (metric && metric.resultStatus) return metric.resultStatus;
    if (inputVariantKeys.has(key)) return 'input';
    return isMissingMetric(metric) ? 'not_started' : 'succeeded';
}

function renderMetricCaption(obj, key) {
    if (key === 'target') {
        // The target column intentionally shows no metrics, but it must still
        // reserve the same caption height as the other columns so the image
        // stays top-aligned (parallel) with them instead of centering.
        return `<div class="demo-metrics is-placeholder" aria-hidden="true">
            <span class="demo-metric metric-p">P --</span>
            <span class="demo-metric metric-v">V --</span>
            <span class="demo-metric metric-wt">--</span>
        </div>`;
    }
    const resultStatus = resultStatusForCell(obj, key);
    if (resultStatus === 'not_started' || resultStatus === 'failed') return '';
    const isInputVariant = inputVariantKeys.has(key);
    const metric = metricForCell(obj, key);
    if (!metric || metric.available === false) {
        return `<div class="demo-metrics is-missing" title="No mesh found for this cell">
            <span class="demo-metric metric-p">P --</span>
            <span class="demo-metric metric-v">V --</span>
            <span class="demo-metric metric-wt">--</span>
            ${isInputVariant ? '' : '<span class="demo-metric metric-t">T --</span>'}
        </div>`;
    }

    const watertightClass = metric.watertight === true
        ? 'is-good'
        : (metric.watertight === false ? 'is-bad' : '');
    const title = [
        `Parts: ${formatMetricNumber(metric.parts)}`,
        `Vertices: ${formatMetricNumber(metric.vertices)}`,
        `Watertight: ${formatWatertight(metric.watertight)}`,
        isInputVariant || metric.inferenceTimeSeconds == null ? null : `Inference time: ${formatInferenceTime(metric.inferenceTimeSeconds)}`
    ].filter(Boolean).join(' | ');

    return `<div class="demo-metrics" title="${escapeAttribute(title)}">
        <span class="demo-metric metric-p">P ${formatMetricNumber(metric.parts)}</span>
        <span class="demo-metric metric-v">V ${formatMetricNumber(metric.vertices)}</span>
        <span class="demo-metric metric-wt ${watertightClass}">${formatWatertight(metric.watertight)}</span>
        ${isInputVariant ? '' : `<span class="demo-metric metric-t">T ${formatInferenceTime(metric.inferenceTimeSeconds)}</span>`}
    </div>`;
}
// Optional note shown under an object's name. Anything not listed has no note.
const demoNotes = {
  water_manhole_cover: "Thin details; mesh is not watertight."
};
/*
  water_manhole_cover: "闈炴按瀵嗗寘鍚杽鐗?
*/

function renderGallery(containerId, objects, baseFolder, columns = demoColumns, options = {}) {
    const container = document.getElementById(containerId);
    if (!container) return;
    const showMetrics = options.showMetrics !== false;
    container.style.setProperty('--demo-column-count', columns.length);

    const shell = document.createElement('div');
    shell.className = 'demo-gallery-shell';

    const viewport = document.createElement('div');
    viewport.className = 'demo-gallery-viewport';
    viewport.setAttribute('role', 'region');
    viewport.setAttribute('aria-label', `${baseFolder.replace(/_/g, ' ')} comparison gallery`);

    const stack = document.createElement('div');
    stack.className = 'demo-gallery-stack';

    // Header row
    const headerDiv = document.createElement('div');
    headerDiv.className = 'demo-header';
    headerDiv.innerHTML = `<div class="demo-header-label"></div>` +
        columns.map(c => `<div class="demo-header-label">${c.label}</div>`).join('');
    stack.appendChild(headerDiv);

    // One row per object
    objects.forEach(obj => {
        const row = document.createElement('div');
        row.className = 'demo-row';
        const cells = columns.map(c => {
            const src = `static/images/${baseFolder}/${obj}/${c.src}`;
            const caption = showMetrics ? renderMetricCaption(obj, c.key) : '';
            const resultStatus = resultStatusForCell(obj, c.key);
            const imageMarkup = resultStatus === 'failed'
                ? '<img src="static/images/generation_error.png" alt="Generation failed">'
                : `<img src="${src}" alt="${c.label}"
                         onerror="this.parentElement.classList.add('empty'); this.remove();">`;
            return `<div class="demo-cell-wrap">
                <div class="demo-cell">
                    ${imageMarkup}
                </div>
                ${caption}
            </div>`;
        }).join('');
        const note = demoNotes[obj] ? `<span class="demo-row-note">${demoNotes[obj]}</span>` : '';
        row.innerHTML = `<div class="demo-row-label">${prettyLabel(obj)}${note}</div>${cells}`;
        stack.appendChild(row);
    });

    const scrollbar = document.createElement('div');
    scrollbar.className = 'demo-scrollbar';
    scrollbar.innerHTML = `
        <div class="demo-scrollbar-track" aria-hidden="true">
            <div class="demo-scrollbar-thumb"></div>
        </div>`;

    viewport.appendChild(stack);
    shell.appendChild(viewport);
    shell.appendChild(scrollbar);
    container.appendChild(shell);
    setupGalleryScroller(shell, viewport, scrollbar.querySelector('.demo-scrollbar-thumb'));
}

function setupGalleryScroller(shell, viewport, thumb) {
    if (!shell || !viewport || !thumb) return;

    let isDraggingViewport = false;
    let isDraggingThumb = false;
    let dragStartX = 0;
    let dragStartScrollLeft = 0;
    let thumbStartLeft = 0;

    const maxScroll = () => Math.max(0, viewport.scrollWidth - viewport.clientWidth);
    const thumbTrack = () => thumb.parentElement;
    const maxThumbLeft = () => Math.max(0, thumbTrack().clientWidth - thumb.offsetWidth);

    function updateScrollState() {
        const scrollMax = maxScroll();
        const hasOverflow = scrollMax > 1;
        shell.classList.toggle('can-scroll-left', viewport.scrollLeft > 1);
        shell.classList.toggle('at-scroll-end', !hasOverflow || viewport.scrollLeft >= scrollMax - 1);
        thumbTrack().style.display = hasOverflow ? 'block' : 'none';
        if (!hasOverflow) return;

        const visibleRatio = viewport.clientWidth / viewport.scrollWidth;
        const thumbWidth = Math.max(44, thumbTrack().clientWidth * visibleRatio);
        const left = (viewport.scrollLeft / scrollMax) * Math.max(0, thumbTrack().clientWidth - thumbWidth);
        thumb.style.width = `${thumbWidth}px`;
        thumb.style.transform = `translateX(${left}px)`;
    }

    viewport.addEventListener('scroll', updateScrollState, { passive: true });
    window.addEventListener('resize', updateScrollState);

    viewport.addEventListener('pointerdown', (event) => {
        if (event.button !== 0 || event.target.closest('.demo-scrollbar')) return;
        isDraggingViewport = true;
        dragStartX = event.clientX;
        dragStartScrollLeft = viewport.scrollLeft;
        viewport.classList.add('is-dragging');
        viewport.setPointerCapture(event.pointerId);
    });

    viewport.addEventListener('pointermove', (event) => {
        if (!isDraggingViewport) return;
        viewport.scrollLeft = dragStartScrollLeft - (event.clientX - dragStartX);
    });

    function stopViewportDrag(event) {
        if (!isDraggingViewport) return;
        isDraggingViewport = false;
        viewport.classList.remove('is-dragging');
        if (viewport.hasPointerCapture(event.pointerId)) {
            viewport.releasePointerCapture(event.pointerId);
        }
    }

    viewport.addEventListener('pointerup', stopViewportDrag);
    viewport.addEventListener('pointercancel', stopViewportDrag);
    viewport.addEventListener('mouseleave', () => {
        isDraggingViewport = false;
        viewport.classList.remove('is-dragging');
    });

    thumb.addEventListener('pointerdown', (event) => {
        event.preventDefault();
        isDraggingThumb = true;
        dragStartX = event.clientX;
        const matrix = new DOMMatrixReadOnly(getComputedStyle(thumb).transform);
        thumbStartLeft = Number.isFinite(matrix.m41) ? matrix.m41 : 0;
        thumb.classList.add('is-dragging');
        thumb.setPointerCapture(event.pointerId);
    });

    thumb.addEventListener('pointermove', (event) => {
        if (!isDraggingThumb) return;
        const nextLeft = Math.min(maxThumbLeft(), Math.max(0, thumbStartLeft + event.clientX - dragStartX));
        viewport.scrollLeft = maxScroll() * (nextLeft / Math.max(1, maxThumbLeft()));
    });

    function stopThumbDrag(event) {
        if (!isDraggingThumb) return;
        isDraggingThumb = false;
        thumb.classList.remove('is-dragging');
        if (thumb.hasPointerCapture(event.pointerId)) {
            thumb.releasePointerCapture(event.pointerId);
        }
    }

    thumb.addEventListener('pointerup', stopThumbDrag);
    thumb.addEventListener('pointercancel', stopThumbDrag);
    requestAnimationFrame(updateScrollState);
}

async function loadGallery() {
    try {
        demoColumns = columnsFromVariants(galleryConfig.columns);
        let multipart = galleryConfig.groups.multipart;
        let singlepart = galleryConfig.groups.singlepart;
        if (!multipart.objects?.length && !singlepart.objects?.length) {
            const inferredGroups = await inferGalleryGroupsFromMetrics();
            multipart = inferredGroups.multipart;
            singlepart = inferredGroups.singlepart;
        }
        renderGallery('video-items-multipart', multipart.objects, multipart.baseFolder);
        renderGallery('video-items-singlepart', singlepart.objects, singlepart.baseFolder);
    } catch (error) {
        console.error('Loading failed:', error);
    }
}

window.addEventListener('DOMContentLoaded', loadGallery);

})();






